h1{
    text-align: center;
    font-size: 40px;
    letter-spacing: 10px;
}

.home-img-container {
  position: relative;
  display: inline-block;
}
.home-img-container img {
  display: block;
  width: 100%;
  border-radius: 12px;
}
.ver-productos-btn {
  position: absolute;
  top: 18px;
  right: 18px;
  background: #1a8917;
  color: #fff;
  border: none;
  border-radius: 6px;
  padding: 8px 18px;
  font-size: 1rem;
  cursor: pointer;
  text-decoration: none;
  transition: background 0.2s;
  z-index: 2;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  font-weight: 500;
}
.ver-productos-btn:hover {
  background: #166d13;
}
